const raw = $input.first().json;
const trigger = raw.body || raw;
const {
  owner, repo, system_prompt_path,
  skills_paths = '', base_branch = 'main', max_logs = 5,
} = trigger;
const skill_paths = skills_paths.split(/[,\n]/).map(s => s.trim()).filter(Boolean);
const agent_folder = system_prompt_path.split('/').slice(0, -1).join('/');
const logs_path = agent_folder + '/evals/logs';
return [{ json: { owner, repo, base_branch, pr_base: 'main', system_prompt_path, skill_paths,
                  agent_folder, logs_path, max_logs: Number(max_logs) || 5 } }];

const trigger = $('Parse Trigger').first().json;
if (!trigger.skill_paths || trigger.skill_paths.length === 0) {
  return [{ json: { _sentinel: true } }];
}
return trigger.skill_paths.map(p => ({ json: {
  skill_path: p, owner: trigger.owner, repo: trigger.repo,
  base_branch: trigger.base_branch,
} }));

const trigger = $('Parse Trigger').first().json;
const dec = b64 => Buffer.from((b64 || '').replace(/\n/g, ''), 'base64').toString('utf8');
const skills = $input.all()
  .filter(item => item.json && item.json.content)
  .map(item => ({ path: item.json.path, content: dec(item.json.content), sha: item.json.sha }));
return [{ json: {
  owner: trigger.owner, repo: trigger.repo, base_branch: trigger.base_branch,
  logs_path: trigger.logs_path, max_logs: trigger.max_logs, skills,
} }];

const collectSkillsData = $('Collect Skills').first().json;

// n8n HTTP Request splits JSON array responses into individual items.
// Collect all items; if the first item is itself an array (non-split path), unwrap it.
const allItems = $input.all().map(item => item.json).filter(j => j && !j.error);
const first = allItems[0];
const dir = Array.isArray(first) ? first : allItems;

const entries = dir
  .filter(e => e && e.type === 'file' && typeof e.name === 'string' && e.name.endsWith('.json'))
  .sort((a, b) => b.name.localeCompare(a.name))
  .slice(0, collectSkillsData.max_logs);

if (entries.length === 0) {
  return [{ json: { _no_logs: true } }];
}
return entries.map(e => ({ json: {
  log_path: e.path,
  owner: collectSkillsData.owner,
  repo: collectSkillsData.repo,
  base_branch: collectSkillsData.base_branch,
} }));

const trigger   = $('Parse Trigger').first().json;
const spResp    = $('Fetch System Prompt').first().json;
const csData    = $('Collect Skills').first().json;

const dec = b64 => Buffer.from((b64 || '').replace(/\n/g, ''), 'base64').toString('utf8');

const rawSp       = dec(spResp.content);
const spSha       = spResp.sha;
const qmatch      = rawSp.match(/<!--\s*QUALITY_SCORE[\s\S]*?-->\s*\n*/);
const qualityHeader = qmatch ? qmatch[0] : '';
const cleanSp     = rawSp.replace(/<!--\s*QUALITY_SCORE[\s\S]*?-->\s*\n*/g, '').trim();

const skills = csData.skills || [];

const recentLogs = $input.all()
  .filter(item => item.json && item.json.content && !item.json._no_logs)
  .map(item => {
    try { return JSON.parse(dec(item.json.content)); } catch(e) { return null; }
  }).filter(Boolean);

// Include games in full, in order, until the cumulative char count would exceed
// ~100k tokens (≈400k chars at 4 chars/token). Record every game that didn't fit
// so it can be reported to the analysis LLM.
const CHAR_BUDGET = 400_000;
const discarded = [];
let usedChars = 0;

const logsText = recentLogs.length === 0
  ? '(no eval logs available yet)'
  : (() => {
      const runBlocks = [];
      for (const log of recentLogs) {
        const runHeader = '\n=== Run: ' + log.run_id + ' | ' + log.evaluated_at +
          ' | Success rate: ' + (log.stats && log.stats.success_rate) + '% ===';
        const gameBlocks = [];
        for (const g of (log.games || [])) {
          const block = [
            '\n--- Game #' + g.id + ': ' + (g.success ? 'SUCCESS' : 'FAILED') +
              ' in ' + g.iterations + ' iterations ---',
            ...(g.transcript || []).map(t =>
              (t.role === 'agent' ? 'Agent' : 'User') + ': ' + t.text
            ),
          ].join('\n');
          if (usedChars + block.length > CHAR_BUDGET) {
            discarded.push('run ' + log.run_id + ' game #' + g.id);
          } else {
            usedChars += block.length;
            gameBlocks.push(block);
          }
        }
        if (gameBlocks.length > 0) {
          runBlocks.push(runHeader + gameBlocks.join(''));
        }
      }
      const discardNote = discarded.length === 0 ? '' :
        '\n\n[CONTEXT BUDGET REACHED: ' + discarded.length + ' game(s) omitted — ' +
        discarded.join(', ') + ']';
      return runBlocks.join('\n\n---\n\n') + discardNote;
    })();

const skillsText = skills
  .map(s => '### ' + s.path + '\n\n' + s.content)
  .join('\n\n---\n\n');

const contentMap = Object.assign(
  { [trigger.system_prompt_path]: { content: cleanSp, sha: spSha } },
  ...skills.map(s => ({ [s.path]: { content: s.content, sha: s.sha } }))
);

return [{ json: {
  owner: trigger.owner, repo: trigger.repo, base_branch: trigger.base_branch, pr_base: trigger.pr_base || 'main',
  system_prompt_path: trigger.system_prompt_path, skill_paths: trigger.skill_paths,
  qualityHeader, contentMap,
  llmInput:
    '## System Prompt (' + trigger.system_prompt_path + ')\n\n' + cleanSp + '\n\n' +
    (skillsText ? '## Skill Files\n\n' + skillsText + '\n\n' : '') +
    '## Recent Conversation Logs\n\n' + logsText,
} }];

const llmOutput = $json.text || $json.output || '';
const ctx = $('Assemble LLM Input').first().json;

let improvements;
try {
  const m = llmOutput.match(/\[[\s\S]*\]/);
  improvements = m ? JSON.parse(m[0]) : [];
} catch(e) {
  improvements = [];
}

if (!improvements.length) {
  throw new Error('Analysis found no actionable improvements — no PR will be created.');
}

// Group all improvements by file path so Apply Instructions runs once per file
// with every change bundled, producing one corrected version instead of N partial ones.
const byPath = new Map();
for (const imp of improvements) {
  if (!imp.path || !ctx.contentMap[imp.path]) continue;
  if (!byPath.has(imp.path)) byPath.set(imp.path, { summaries: [], instructions: [] });
  byPath.get(imp.path).summaries.push(imp.change_summary || 'Improvement');
  byPath.get(imp.path).instructions.push(imp.instructions);
}

if (byPath.size === 0) {
  throw new Error('Analysis found no actionable improvements — no PR will be created.');
}

return Array.from(byPath.entries()).map(([path, group]) => {
  const fileData = ctx.contentMap[path];
  const combinedInstructions = group.instructions.length === 1
    ? group.instructions[0]
    : 'Apply ALL of the following changes:\n\n' +
      group.instructions.map((inst, i) => (i + 1) + '. ' + inst).join('\n\n');
  return { json: {
    path,
    change_summary: group.summaries.join('; '),
    instructions: combinedInstructions,
    original_content: fileData.content,
    original_sha: fileData.sha,
    owner: ctx.owner, repo: ctx.repo, base_branch: ctx.base_branch,
    system_prompt_path: ctx.system_prompt_path, qualityHeader: ctx.qualityHeader,
    pr_base: ctx.pr_base || 'main',
  } };
});

